#include "game/combat/EnemySystem.h"
#include "raymath.h"
namespace fw { void EnemySystem::Update(std::vector<EnemyInstance>& enemies, const Vector3& playerPos, int& playerHealth, float dt) const { for(auto& e:enemies){ if(!e.alive) continue; if(e.hurtFlash>0.0f) e.hurtFlash-=dt; Vector3 toPlayer=Vector3Subtract(playerPos,e.position); float dist=Vector3Length(toPlayer); float moveSpeed=e.type=="wolf"?4.5f:(e.type=="brute"?2.0f:3.0f); if(dist>0.001f&&dist<18.0f){ Vector3 dir=Vector3Scale(Vector3Normalize(toPlayer),moveSpeed*dt); e.position=Vector3Add(e.position,{dir.x,0.0f,dir.z}); } if(e.attackCooldown>0.0f) e.attackCooldown-=dt; if(dist<1.75f&&e.attackCooldown<=0.0f){ int damage=e.type=="brute"?14:(e.type=="wolf"?6:8); playerHealth-=damage; e.attackCooldown=e.type=="wolf"?0.7f:1.1f; } } } }
